async function handleRegister(request, env, corsHeaders) {
  const body = await request.json();
  const { username, password, email } = body;

  if (!username || !password) {
    return jsonResponse({ error: "Username and password are required" }, 400, corsHeaders);
  }

  if (username.length < 3 || username.length > 50) {
    return jsonResponse({ error: "Username must be between 3 and 50 characters" }, 400, corsHeaders);
  }

  if (password.length < 8) {
    return jsonResponse({ error: "Password must be at least 8 characters" }, 400, corsHeaders);
  }

  const existingUser = await env.USER_DB.get(`user:${username.toLowerCase()}`);
  if (existingUser) {
    return jsonResponse({ error: "Username already exists" }, 409, corsHeaders);
  }

  const salt = generateSalt();
  const hashedPassword = await hashPassword(password, salt);

  const userData = {
    username: username.toLowerCase(),
    email: email || null,
    passwordHash: hashedPassword,
    salt: salt,
    createdAt: new Date().toISOString(),
    failedLoginAttempts: 0,
    lockedUntil: null,
  };

  await env.USER_DB.put(`user:${username.toLowerCase()}`, JSON.stringify(userData));

  const apiKey = await env.CONFIG_STORE.get("REGISTRATION_API_KEY");
  if (apiKey) {
    await logEvent(env, "user_registered", { username: username.toLowerCase() });
  }

  return jsonResponse({
    success: true,
    message: "User registered successfully",
    username: username.toLowerCase(),
  }, 201, corsHeaders);
}

async function handleLogin(request, env, corsHeaders) {
  const body = await request.json();
  const { username, password } = body;

  if (!username || !password) {
    return jsonResponse({ error: "Username and password are required" }, 400, corsHeaders);
  }

  const userDataRaw = await env.USER_DB.get(`user:${username.toLowerCase()}`);
  if (!userDataRaw) {
    return jsonResponse({ error: "Invalid username or password" }, 401, corsHeaders);
  }

  const userData = JSON.parse(userDataRaw);

  if (userData.lockedUntil) {
    const lockExpiry = new Date(userData.lockedUntil);
    if (lockExpiry > new Date()) {
      const remainingSeconds = Math.ceil((lockExpiry - new Date()) / 1000);
      return jsonResponse({
        error: "Account is temporarily locked due to too many failed login attempts",
        retryAfterSeconds: remainingSeconds,
      }, 429, corsHeaders);
    } else {
      userData.failedLoginAttempts = 0;
      userData.lockedUntil = null;
    }
  }

  const hashedInput = await hashPassword(password, userData.salt);
  if (!timingSafeEqual(hashedInput, userData.passwordHash)) {
    userData.failedLoginAttempts = (userData.failedLoginAttempts || 0) + 1;

    const maxAttempts = 5;
    if (userData.failedLoginAttempts >= maxAttempts) {
      const lockDurationMinutes = 15;
      userData.lockedUntil = new Date(Date.now() + lockDurationMinutes * 60 * 1000).toISOString();
    }

    await env.USER_DB.put(`user:${username.toLowerCase()}`, JSON.stringify(userData));

    await logEvent(env, "failed_login", {
      username: username.toLowerCase(),
      attempts: userData.failedLoginAttempts,
    });

    return jsonResponse({ error: "Invalid username or password" }, 401, corsHeaders);
  }

  userData.failedLoginAttempts = 0;
  userData.lockedUntil = null;
  userData.lastLoginAt = new Date().toISOString();
  await env.USER_DB.put(`user:${username.toLowerCase()}`, JSON.stringify(userData));

  const sessionToken = generateSessionToken();
  const sessionTTL = 3600;

  const sessionData = {
    username: username.toLowerCase(),
    email: userData.email,
    createdAt: new Date().toISOString(),
    expiresAt: new Date(Date.now() + sessionTTL * 1000).toISOString(),
    userAgent: request.headers.get("User-Agent") || "unknown",
    ip: request.headers.get("CF-Connecting-IP") || "unknown",
  };

  await env.SESSION_STORE.put(`session:${sessionToken}`, JSON.stringify(sessionData), {
    expirationTtl: sessionTTL,
  });

  const userSessionsRaw = await env.SESSION_STORE.get(`user_sessions:${username.toLowerCase()}`);
  let userSessions = userSessionsRaw ? JSON.parse(userSessionsRaw) : [];
  userSessions.push(sessionToken);

  if (userSessions.length > 10) {
    const oldTokens = userSessions.splice(0, userSessions.length - 10);
    for (const oldToken of oldTokens) {
      await env.SESSION_STORE.delete(`session:${oldToken}`);
    }
  }

  await env.SESSION_STORE.put(
    `user_sessions:${username.toLowerCase()}`,
    JSON.stringify(userSessions),
    { expirationTtl: sessionTTL }
  );

  await logEvent(env, "successful_login", { username: username.toLowerCase() });

  return jsonResponse({
    success: true,
    sessionToken: sessionToken,
    expiresIn: sessionTTL,
    username: username.toLowerCase(),
  }, 200, corsHeaders);
}

async function handleValidateSession(request, env, corsHeaders) {
  const authHeader = request.headers.get("Authorization");
  let sessionToken;

  if (authHeader && authHeader.startsWith("Bearer ")) {
    sessionToken = authHeader.substring(7);
  } else {
    const body = await request.json().catch(() => ({}));
    sessionToken = body.sessionToken;
  }

  if (!sessionToken) {
    return jsonResponse({ error: "Session token is required" }, 400, corsHeaders);
  }

  const sessionDataRaw = await env.SESSION_STORE.get(`session:${sessionToken}`);
  if (!sessionDataRaw) {
    return jsonResponse({ valid: false, error: "Invalid or expired session" }, 401, corsHeaders);
  }

  const sessionData = JSON.parse(sessionDataRaw);

  const expiresAt = new Date(sessionData.expiresAt);
  if (expiresAt <= new Date()) {
    await env.SESSION_STORE.delete(`session:${sessionToken}`);
    return jsonResponse({ valid: false, error: "Session has expired" }, 401, corsHeaders);
  }

  return jsonResponse({
    valid: true,
    username: sessionData.username,
    email: sessionData.email,
    sessionCreatedAt: sessionData.createdAt,
    expiresAt: sessionData.expiresAt,
  }, 200, corsHeaders);
}

async function handleLogout(request, env, corsHeaders) {
  const authHeader = request.headers.get("Authorization");
  let sessionToken;

  if (authHeader && authHeader.startsWith("Bearer ")) {
    sessionToken = authHeader.substring(7);
  } else {
    const body = await request.json().catch(() => ({}));
    sessionToken = body.sessionToken;
  }

  if (!sessionToken) {
    return jsonResponse({ error: "Session token is required" }, 400, corsHeaders);
  }

  const sessionDataRaw = await env.SESSION_STORE.get(`session:${sessionToken}`);
  if (sessionDataRaw) {
    const sessionData = JSON.parse(sessionDataRaw);

    const userSessionsRaw = await env.SESSION_STORE.get(`user_sessions:${sessionData.username}`);
    if (userSessionsRaw) {
      let userSessions = JSON.parse(userSessionsRaw);
      userSessions = userSessions.filter((t) => t !== sessionToken);
      if (userSessions.length > 0) {
        await env.SESSION_STORE.put(
          `user_sessions:${sessionData.username}`,
          JSON.stringify(userSessions),
          { expirationTtl: 3600 }
        );
      } else {
        await env.SESSION_STORE.delete(`user_sessions:${sessionData.username}`);
      }
    }

    await env.SESSION_STORE.delete(`session:${sessionToken}`);
    await logEvent(env, "logout", { username: sessionData.username });
  }

  return jsonResponse({ success: true, message: "Logged out successfully" }, 200, corsHeaders);
}

async function handleRefreshSession(request, env, corsHeaders) {
  const authHeader = request.headers.get("Authorization");
  let sessionToken;

  if (authHeader && authHeader.startsWith("Bearer ")) {
    sessionToken = authHeader.substring(7);
  } else {
    const body = await request.json().catch(() => ({}));
    sessionToken = body.sessionToken;
  }

  if (!sessionToken) {
    return jsonResponse({ error: "Session token is required" }, 400, corsHeaders);
  }

  const sessionDataRaw = await env.SESSION_STORE.get(`session:${sessionToken}`);
  if (!sessionDataRaw) {
    return jsonResponse({ error: "Invalid or expired session" }, 401, corsHeaders);
  }

  const oldSessionData = JSON.parse(sessionDataRaw);

  await env.SESSION_STORE.delete(`session:${sessionToken}`);

  const newSessionToken = generateSessionToken();
  const sessionTTL = 3600;

  const newSessionData = {
    username: oldSessionData.username,
    email: oldSessionData.email,
    createdAt: new Date().toISOString(),
    expiresAt: new Date(Date.now() + sessionTTL * 1000).toISOString(),
    userAgent: request.headers.get("User-Agent") || oldSessionData.userAgent,
    ip: request.headers.get("CF-Connecting-IP") || oldSessionData.ip,
    refreshedFrom: sessionToken.substring(0, 8) + "...",
  };

  await env.SESSION_STORE.put(`session:${newSessionToken}`, JSON.stringify(newSessionData), {
    expirationTtl: sessionTTL,
  });

  const userSessionsRaw = await env.SESSION_STORE.get(`user_sessions:${oldSessionData.username}`);
  if (userSessionsRaw) {
    let userSessions = JSON.parse(userSessionsRaw);
    userSessions = userSessions.filter((t) => t !== sessionToken);
    userSessions.push(newSessionToken);
    await env.SESSION_STORE.put(
      `user_sessions:${oldSessionData.username}`,
      JSON.stringify(userSessions),
      { expirationTtl: sessionTTL }
    );
  }

  return jsonResponse({
    success: true,
    sessionToken: newSessionToken,
    expiresIn: sessionTTL,
    username: oldSessionData.username,
  }, 200, corsHeaders);
}

function generateSalt() {
  const array = new Uint8Array(16);
  crypto.getRandomValues(array);
  return arrayBufferToHex(array);
}

function generateSessionToken() {
  const array = new Uint8Array(32);
  crypto.getRandomValues(array);
  return arrayBufferToHex(array);
}

async function hashPassword(password, salt) {
  const encoder = new TextEncoder();
  const data = encoder.encode(salt + password);

  let hash = data;
  for (let i = 0; i < 10000; i++) {
    const hashBuffer = await crypto.subtle.digest("SHA-256", hash);
    const combined = new Uint8Array(hashBuffer.byteLength + encoder.encode(salt).byteLength);
    combined.set(new Uint8Array(hashBuffer), 0);
    combined.set(encoder.encode(salt), hashBuffer.byteLength);
    hash = combined;
  }

  const finalHash = await crypto.subtle.digest("SHA-256", hash);
  return arrayBufferToHex(new Uint8Array(finalHash));
}

function timingSafeEqual(a, b) {
  if (a.length !== b.length) {
    return false;
  }
  let result = 0;
  for (let i = 0; i < a.length; i++) {
    result |= a.charCodeAt(i) ^ b.charCodeAt(i);
  }
  return result === 0;
}

function arrayBufferToHex(buffer) {
  return Array.from(buffer)
    .map((b) => b.toString(16).padStart(2, "0"))
    .join("");
}

async function logEvent(env, eventType, data) {
  try {
    const logEntry = {
      eventType,
      timestamp: new Date().toISOString(),
      ...data,
    };

    const logKey = `log:${eventType}:${Date.now()}:${Math.random().toString(36).substring(2, 8)}`;
    await env.SESSION_STORE.put(logKey, JSON.stringify(logEntry), {
      expirationTtl: 86400,
    });
  } catch (err) {
    console.error("Failed to log event:", err);
  }
}

function jsonResponse(data, status = 200, corsHeaders = {}) {
  return new Response(JSON.stringify(data), {
    status,
    headers: {
      "Content-Type": "application/json",
      ...corsHeaders,
    },
  });
}